import asyncio
from decimal import Decimal
from db.db import async_session, engine, Base
from models.models import Product, RiskProfile
import models.models # Ensure models are tracked

async def seed_data():
    # Create tables first if they don't exist
    async with engine.begin() as conn:
        await conn.run_sync(Base.metadata.create_all)

    async with async_session() as session:
        async with session.begin():
            # 1. Create Risk Profiles
            profiles = [
                RiskProfile(risk_group=1, interest_rate_modifier=0.20, required_deposit_percent=0.15),
                RiskProfile(risk_group=2, interest_rate_modifier=0.15, required_deposit_percent=0.10),
                RiskProfile(risk_group=3, interest_rate_modifier=0.10, required_deposit_percent=0.05),
            ]
            
            # 2. Create Products
            products = [
                Product(brand="Samsung", model_name="Galaxy A15", base_cash_price=Decimal("3200.00"), stock_level=50, model_image="data:image/jpeg;base64,"),
                Product(brand="Apple", model_name="iPhone 13", base_cash_price=Decimal("12000.00"), stock_level=10, model_image="data:image/jpeg;base64,"),
                Product(brand="Nokia", model_name="C22", base_cash_price=Decimal("2500.00"), stock_level=100, model_image="data:image/jpeg;base64,"),
                Product(brand="Samsung", model_name="Galaxy A16", base_cash_price=Decimal("2340.00"), stock_level=45, model_image="data:image/jpeg;base64,"),
                Product(brand="Moterola", model_name="G75", base_cash_price=Decimal("4440.00"), stock_level=15, model_image="data:image/jpeg;base64,"),
                Product(brand="Apple", model_name="iPhone 15", base_cash_price=Decimal("16550.00"), stock_level=36, model_image="data:image/jpeg;base64,"),
            ]
            
            session.add_all(profiles)
            session.add_all(products)
            
        await session.commit()
    print("Database tables created and seeded successfully!")

if __name__ == "__main__":
    asyncio.run(seed_data())